class Solution(object):
    def minStable(self, nums, maxC):
        """
        :type nums: List[int]
        :type maxC: int
        :rtype: int
        """
        from math import gcd
        from functools import reduce

        def compute_gcd(arr):
            return reduce(gcd, arr)

        def can_achieve(target_len):
            # Check if we can reduce max stable subarray length to < target_len using at most maxC edits
            edits_needed = 0
            i = 0
            while i < len(nums):
                # Check subarrays of length target_len + 1
                if i + target_len < len(nums):
                    subarray = nums[i:i+target_len+1]
                    if compute_gcd(subarray) >= 2:
                        # This subarray is stable, we need to break it
                        edits_needed += 1
                        i += target_len + 1
                    else:
                        i += 1
                else:
                    break

            return edits_needed <= maxC

        # Binary search on answer
        left, right = 1, len(nums)
        result = len(nums)

        while left <= right:
            mid = (left + right) // 2
            if can_achieve(mid):
                result = mid
                right = mid - 1
            else:
                left = mid + 1

        return result
